{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyNPPNjBQxTmp/sy+GnOw6WW"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":1,"metadata":{"id":"M-TWis0rUuRB","executionInfo":{"status":"ok","timestamp":1773122314831,"user_tz":-180,"elapsed":126,"user":{"displayName":"Bassem Amin","userId":"03844483762484690298"}}},"outputs":[],"source":["\"\"\"\n","content.py\n","-----------\n","Defines the Content class representing a video item in the StreamFlix catalogue,\n","and the ContentCatalogue class that manages a collection of Content objects.\n","\n","Author: [Your Name]\n","Date: [Submission Date]\n","\"\"\"\n","\n","\n","class Content:\n","    \"\"\"\n","    Represents a single video content item on the StreamFlix platform.\n","\n","    Attributes:\n","        __content_id (int): Unique identifier for the content.\n","        __title (str): Title of the content.\n","        __genre (str): Genre category (e.g., Action, Drama, Comedy).\n","        __release_year (int): Year the content was released.\n","        __duration (int): Duration in minutes.\n","        __rating (float): Average user rating (0.0 - 10.0).\n","        __availability_status (bool): Whether the content is currently available.\n","        __content_type (str): Category type — 'Movie', 'TV Series', or 'Documentary'.\n","        __premium (bool): Whether this content requires premium access or pay-per-view.\n","    \"\"\"\n","\n","    _id_counter = 1000  # Class-level auto-increment counter\n","\n","    def __init__(self, title: str, genre: str, release_year: int, duration: int,\n","                 rating: float, content_type: str, premium: bool = False,\n","                 availability_status: bool = True):\n","        \"\"\"\n","        Initialise a new Content instance.\n","\n","        Args:\n","            title (str): Title of the video content.\n","            genre (str): Genre of the content.\n","            release_year (int): Year of release.\n","            duration (int): Duration in minutes.\n","            rating (float): Average rating (0.0–10.0).\n","            content_type (str): One of 'Movie', 'TV Series', 'Documentary'.\n","            premium (bool): True if premium/pay-per-view content. Default False.\n","            availability_status (bool): True if available for streaming. Default True.\n","\n","        Raises:\n","            ValueError: If rating is outside 0–10 or content_type is invalid.\n","        \"\"\"\n","        if not (0.0 <= rating <= 10.0):\n","            raise ValueError(\"Rating must be between 0.0 and 10.0.\")\n","        valid_types = ['Movie', 'TV Series', 'Documentary']\n","        if content_type not in valid_types:\n","            raise ValueError(f\"content_type must be one of {valid_types}.\")\n","\n","        Content._id_counter += 1\n","        self.__content_id = Content._id_counter\n","        self.__title = title\n","        self.__genre = genre\n","        self.__release_year = release_year\n","        self.__duration = duration\n","        self.__rating = rating\n","        self.__availability_status = availability_status\n","        self.__content_type = content_type\n","        self.__premium = premium\n","\n","    # ── Getters ──────────────────────────────────────────────\n","    def get_content_id(self) -> int:\n","        \"\"\"Return the unique content ID.\"\"\"\n","        return self.__content_id\n","\n","    def get_title(self) -> str:\n","        \"\"\"Return the title of the content.\"\"\"\n","        return self.__title\n","\n","    def get_genre(self) -> str:\n","        \"\"\"Return the genre.\"\"\"\n","        return self.__genre\n","\n","    def get_release_year(self) -> int:\n","        \"\"\"Return the release year.\"\"\"\n","        return self.__release_year\n","\n","    def get_duration(self) -> int:\n","        \"\"\"Return the duration in minutes.\"\"\"\n","        return self.__duration\n","\n","    def get_rating(self) -> float:\n","        \"\"\"Return the average rating.\"\"\"\n","        return self.__rating\n","\n","    def is_available(self) -> bool:\n","        \"\"\"Return True if the content is available for streaming.\"\"\"\n","        return self.__availability_status\n","\n","    def get_content_type(self) -> str:\n","        \"\"\"Return the content type (Movie / TV Series / Documentary).\"\"\"\n","        return self.__content_type\n","\n","    def is_premium(self) -> bool:\n","        \"\"\"Return True if the content is premium / pay-per-view.\"\"\"\n","        return self.__premium\n","\n","    # ── Mutators ─────────────────────────────────────────────\n","    def get_details(self) -> dict:\n","        \"\"\"\n","        Return a dictionary with all content details.\n","\n","        Returns:\n","            dict: All attributes of this content item.\n","        \"\"\"\n","        return {\n","            'content_id': self.__content_id,\n","            'title': self.__title,\n","            'genre': self.__genre,\n","            'release_year': self.__release_year,\n","            'duration': self.__duration,\n","            'rating': self.__rating,\n","            'availability_status': self.__availability_status,\n","            'content_type': self.__content_type,\n","            'premium': self.__premium\n","        }\n","\n","    def update_details(self, **kwargs) -> None:\n","        \"\"\"\n","        Update content attributes using keyword arguments.\n","\n","        Supported keys: title, genre, release_year, duration, rating,\n","                        availability_status, content_type, premium.\n","\n","        Args:\n","            **kwargs: Attribute names and their new values.\n","\n","        Raises:\n","            ValueError: If an unsupported key is provided.\n","        \"\"\"\n","        allowed = {'title', 'genre', 'release_year', 'duration', 'rating',\n","                    'availability_status', 'content_type', 'premium'}\n","        for key, value in kwargs.items():\n","            if key not in allowed:\n","                raise ValueError(f\"Invalid attribute: {key}\")\n","            if key == 'rating' and not (0.0 <= value <= 10.0):\n","                raise ValueError(\"Rating must be between 0.0 and 10.0.\")\n","            if key == 'content_type' and value not in ['Movie', 'TV Series', 'Documentary']:\n","                raise ValueError(\"content_type must be Movie, TV Series, or Documentary.\")\n","            setattr(self, f'_Content__{key}', value)\n","\n","    def set_availability(self, status: bool) -> None:\n","        \"\"\"\n","        Set the availability status of the content.\n","\n","        Args:\n","            status (bool): True to make available, False to make unavailable.\n","        \"\"\"\n","        self.__availability_status = status\n","\n","    def __str__(self) -> str:\n","        \"\"\"Return a user-friendly string representation of the content.\"\"\"\n","        status = \"Available\" if self.__availability_status else \"Unavailable\"\n","        premium_tag = \" [PREMIUM]\" if self.__premium else \"\"\n","        return (f\"[{self.__content_id}] {self.__title} ({self.__content_type}) \"\n","                f\"- {self.__genre}, {self.__release_year}, {self.__duration}min, \"\n","                f\"Rating: {self.__rating}/10, {status}{premium_tag}\")\n","\n","\n","class ContentCatalogue:\n","    \"\"\"\n","    Manages the full catalogue of Content items available on StreamFlix.\n","    Uses composition — the catalogue owns and controls the lifecycle of its content.\n","\n","    Attributes:\n","        __catalogue (list[Content]): Internal list of Content objects.\n","    \"\"\"\n","\n","    def __init__(self):\n","        \"\"\"Initialise an empty content catalogue.\"\"\"\n","        self.__catalogue: list[Content] = []\n","\n","    def add_content(self, content: Content) -> None:\n","        \"\"\"\n","        Add a Content object to the catalogue.\n","\n","        Args:\n","            content (Content): The content item to add.\n","\n","        Raises:\n","            TypeError: If the argument is not a Content instance.\n","            ValueError: If content with the same ID already exists.\n","        \"\"\"\n","        if not isinstance(content, Content):\n","            raise TypeError(\"Only Content instances can be added to the catalogue.\")\n","        for c in self.__catalogue:\n","            if c.get_content_id() == content.get_content_id():\n","                raise ValueError(f\"Content with ID {content.get_content_id()} already exists.\")\n","        self.__catalogue.append(content)\n","\n","    def remove_content(self, content_id: int) -> None:\n","        \"\"\"\n","        Remove a content item by its ID.\n","\n","        Args:\n","            content_id (int): The ID of the content to remove.\n","\n","        Raises:\n","            ValueError: If no content with the given ID is found.\n","        \"\"\"\n","        for i, c in enumerate(self.__catalogue):\n","            if c.get_content_id() == content_id:\n","                self.__catalogue.pop(i)\n","                return\n","        raise ValueError(f\"Content with ID {content_id} not found in catalogue.\")\n","\n","    def search_content(self, title: str) -> list:\n","        \"\"\"\n","        Search for content whose title contains the given substring (case-insensitive).\n","\n","        Args:\n","            title (str): The search term.\n","\n","        Returns:\n","            list[Content]: Matching content items.\n","        \"\"\"\n","        return [c for c in self.__catalogue if title.lower() in c.get_title().lower()]\n","\n","    def filter_by_genre(self, genre: str) -> list:\n","        \"\"\"\n","        Filter content by genre (case-insensitive).\n","\n","        Args:\n","            genre (str): Genre to filter by.\n","\n","        Returns:\n","            list[Content]: Content items matching the genre.\n","        \"\"\"\n","        return [c for c in self.__catalogue if c.get_genre().lower() == genre.lower()]\n","\n","    def filter_by_type(self, content_type: str) -> list:\n","        \"\"\"\n","        Filter content by type (Movie, TV Series, Documentary).\n","\n","        Args:\n","            content_type (str): Type to filter by.\n","\n","        Returns:\n","            list[Content]: Matching content items.\n","        \"\"\"\n","        return [c for c in self.__catalogue\n","                if c.get_content_type().lower() == content_type.lower()]\n","\n","    def get_all_content(self) -> list:\n","        \"\"\"\n","        Return a copy of the full catalogue list.\n","\n","        Returns:\n","            list[Content]: All content items.\n","        \"\"\"\n","        return list(self.__catalogue)\n","\n","    def __str__(self) -> str:\n","        \"\"\"Return a formatted string of the entire catalogue.\"\"\"\n","        if not self.__catalogue:\n","            return \"ContentCatalogue: [Empty]\"\n","        lines = [\"=\" * 60, \"       StreamFlix Content Catalogue\", \"=\" * 60]\n","        for c in self.__catalogue:\n","            lines.append(str(c))\n","        lines.append(\"=\" * 60)\n","        lines.append(f\"Total items: {len(self.__catalogue)}\")\n","        return \"\\n\".join(lines)"]}]}